    codeSolution: "using System;\n\nclass Program\n{\n    static void Main()\n    {\n        // Action with no parameters\n        Action greet = () => Console.WriteLine(\"Hello World!\");\n        greet();\n        \n        // Action with 1 parameter\n        Action<string> print = msg => Console.WriteLine(msg);\n        print(\"Action with one parameter\");\n        \n        // Action with 2 parameters\n        Action<string, int> repeat = (msg, count) =>\n        {\n            for (int i = 0; i < count; i++)\n                Console.WriteLine($\"{i + 1}: {msg}\");\n        };\n        repeat(\"Hello\", 3);\n        \n        // Action with 3 parameters\n        Action<string, int, bool> log = (msg, level, showTime) =>\n        {\n            string prefix = showTime ? $\"[{DateTime.Now:T}] \" : \"\";\n            Console.WriteLine($\"{prefix}Level {level}: {msg}\");\n        };\n        log(\"Error occurred\", 3, true);\n    }\n}",
    hint: "Action delegates are predefined for void methods (up to 16 parameters).",
