    id: "cs_delegates_14",
    topicId: "cs_delegates",
    question: "Use delegate with BeginInvoke and EndInvoke (APM pattern).",
    mathSolution: "Asynchronous Programming Model with delegates.",
    codeSolution: "using System;\nusing System.Threading;\n\npublic delegate string DataProcessor(string input);\n\nclass Program\n{\n    static void Main()\n    {\n        Console.WriteLine(\"=== APM Pattern with Delegates ===\\n\");\n        \n        DataProcessor processor = ProcessData;\n        \n        // Begin async operation with callback\n        IAsyncResult result = processor.BeginInvoke(\"Hello World\", ar =>\n        {\n            DataProcessor del = (DataProcessor)ar.AsyncState;\n            string output = del.EndInvoke(ar);\n            Console.WriteLine($\"Async result: {output}\");\n        }, processor);\n        \n        // Poll for completion\n        while (!result.IsCompleted)\n        {\n            Console.WriteLine(\"Waiting for completion...\");\n            Thread.Sleep(200);\n        }\n        \n        Console.WriteLine(\"Main thread done\");\n    }\n    \n    static string ProcessData(string input)\n    {\n        Console.WriteLine($\"Processing: {input}\");\n        Thread.Sleep(1500);\n        return input.ToUpper();\n    }\n}",
    hint: "APM pattern uses BeginInvoke/EndInvoke; prefer Task-based async in modern code.",
